const body = $json.body ?? $json;
const sessionId = String(body.session_id ?? '').trim();
const role = String(body.role ?? '').trim();
const message = String(body.message ?? '').trim();
const metadata = (body.metadata && typeof body.metadata === 'object') ? body.metadata : {};
if (!sessionId) throw new Error('session_id is required');
if (!['user', 'assistant', 'system', 'tool'].includes(role)) throw new Error('invalid role');
if (!message) throw new Error('message is required');
const tokenExpected = $env.AGENT_WORKFLOW_TOKEN || '';
const tokenProvided = String(body.token ?? '');
if (tokenExpected && tokenProvided !== tokenExpected) throw new Error('invalid token');
const identRe = /^[A-Za-z_][A-Za-z0-9_]{0,62}$/;
const memorySchema = String($env.AGENT_MEMORY_SCHEMA || 'agent').trim();
const memoryTable = String($env.AGENT_MEMORY_TABLE || 'agent_memory_messages').trim();
if (!identRe.test(memorySchema)) throw new Error('invalid AGENT_MEMORY_SCHEMA');
if (!identRe.test(memoryTable)) throw new Error('invalid AGENT_MEMORY_TABLE');
const metadataJson = JSON.stringify(metadata);
return [{
  json: {
    session_id: sessionId,
    role,
    message,
    metadata,
    session_id_sql: sessionId.replace(/'/g, "''"),
    role_sql: role.replace(/'/g, "''"),
    message_sql: message.replace(/'/g, "''"),
    metadata_sql: metadataJson.replace(/'/g, "''"),
    memory_schema_sql: memorySchema,
    memory_table_sql: memoryTable
  }
}];

const row = items[0]?.json ?? {};
return [{
  json: {
    ok: true,
    inserted_id: row.id ?? null,
    session_id: row.session_id ?? null,
    role: row.role ?? null,
    created_at: row.created_at ?? null
  }
}];
